export default function diff(t,e){let n=[];for(const f in t)if(f in e)if(!t[f]||"object"!=typeof t[f]||t[f]instanceof Date)t[f]===e[f]||t[f]instanceof Date&&e[f]instanceof Date&&+t[f]==+e[f]||n.push({path:[f],type:"CHANGE",value:e[f]});else{const a=diff(t[f],e[f]);n.push(...a.map(t=>(t.path.unshift(f),t)))}else n.push({type:"REMOVE",path:[f]});for(const p in e)p in t||n.push({type:"CREATE",path:[p],value:e[p]});return n}